async def _approve_user_access(
    target: dict,
    *,
    actor_label: str,
    reason: Optional[str] = None,
    organization_id: Optional[str] = None,
    organization_name: Optional[str] = None,
    organization_type: Optional[str] = None,
    school_name: Optional[str] = None,
    manager_email: Optional[str] = None,
    tenant_role: Optional[str] = None,
    approval_note: Optional[str] = None,
) -> dict:
    from app.services.notification_service import NotificationService

    user_id = target["id"]
    now = datetime.now(timezone.utc).isoformat()
    target_for_assignment = dict(target)
    if tenant_role:
        target_for_assignment["tenant_role"] = _clean_optional_string(tenant_role)
    resolved_org_name = organization_name
    resolved_org_type = organization_type
    if organization_id and organization_id != "__create_new__":
        organization_doc = await db.organizations.find_one({"id": organization_id}, {"_id": 0})
        if organization_doc:
            resolved_org_name = organization_doc.get("name")
            resolved_org_type = organization_doc.get("organization_type")
        else:
            resolved_org_name = organization_name or _access_request_workspace_name(target)
    if organization_id == "__create_new__" and not resolved_org_name:
        resolved_org_name = _access_request_workspace_name(target)
    tenancy_updates = await _assign_user_to_tenant_on_approval(
        target=target_for_assignment,
        organization_name=resolved_org_name,
        organization_type=resolved_org_type,
        school_name=school_name or target.get("school_name") or target.get("requested_school_name"),
        manager_email=manager_email,
        actor_label=actor_label,
    )
    updates = {
        "approval_status": "approved",
        "approved_at": now,
        "approved_by": actor_label,
        "revoked_at": None,
        "revoked_by": None,
        "is_active": True,
        **tenancy_updates,
    }
    note = approval_note if approval_note is not None else reason
    if note:
        updates["approval_note"] = note
    await db.users.update_one({"id": user_id}, {"$set": updates})
    updated = await db.users.find_one({"id": user_id}, {"_id": 0, "password": 0})
    await _sync_teacher_admin_link_for_user(updated)
    await _log_auth_event(
        "approval_granted",
        email=updated.get("email"),
        user_id=updated.get("id"),
        result="success",
        reason=note,
    )
    notification = await NotificationService().send_access_approved(
        updated,
        updated.get("school_name") or updated.get("organization_name") or resolved_org_name,
        approval_note=note,
    )
    notification_payload = notification.get("payload") if isinstance(notification, dict) else {}
    updated["_email_delivery_attempted"] = True
    updated["_email_delivery_succeeded"] = bool((notification_payload or {}).get("email_delivery_succeeded"))
    return updated


async def _revoke_user_access(
    target: dict,
    *,
    actor_label: str,
    reason: Optional[str] = None,
) -> dict:
    from app.services.notification_service import NotificationService

    user_id = target["id"]
    now = datetime.now(timezone.utc).isoformat()
    updates = {
        "approval_status": "revoked",
        "revoked_at": now,
        "revoked_by": actor_label,
        "is_active": False,
    }
    if reason:
        updates["approval_note"] = reason
    await db.users.update_one({"id": user_id}, {"$set": updates})
    updated = await db.users.find_one({"id": user_id}, {"_id": 0, "password": 0})
    event_type = "approval_denied" if _get_user_approval_status(target) == "pending" else "access_revoked"
    await _log_auth_event(
        event_type,
        email=updated.get("email"),
        user_id=updated.get("id"),
        result="success",
        reason=reason,
    )
    if _get_user_approval_status(target) == "pending":
        await NotificationService().send_access_rejected(updated, reason)
    return updated


async def _reactivate_user_access(
    target: dict,
    *,
    actor_label: str,
    reason: Optional[str] = None,
) -> dict:
    user_id = target["id"]
    now = datetime.now(timezone.utc).isoformat()
    organization_doc = None
    if target.get("organization_id"):
        organization_doc = await db.organizations.find_one({"id": target["organization_id"]}, {"_id": 0})
    await _enforce_organization_seat_limit(
        organization_doc=organization_doc,
        exclude_user_id=user_id,
    )
    updates = {
        "approval_status": "approved",
        "approved_at": target.get("approved_at") or now,
        "approved_by": actor_label,
        "revoked_at": None,
        "revoked_by": None,
        "is_active": True,
    }
    if reason:
        updates["approval_note"] = reason
    await db.users.update_one({"id": user_id}, {"$set": updates})
    updated = await db.users.find_one({"id": user_id}, {"_id": 0, "password": 0})
    await _log_auth_event(
        "access_reactivated",
        email=updated.get("email"),
        user_id=updated.get("id"),
        result="success",
        reason=reason,
    )
    return updated


async def _hard_delete_user_access(
    target: dict,
    *,
    actor: dict,
    reason: Optional[str] = None,
) -> dict:
    user_id = target["id"]
    email = str(target.get("email") or "").strip().lower()
    deleted_counts: Dict[str, int] = {}
    deleted_snapshot = {
        **{key: value for key, value in target.items() if key != "_id"},
        "approval_status": "deleted",
        "is_active": False,
        "deleted_at": datetime.now(timezone.utc).isoformat(),
        "deleted_by": actor.get("email") or actor.get("id"),
        "account_deleted": True,
        "approval_deleted": _get_user_approval_status(target) == "pending",
    }

    linked_teacher = None
    linked_teacher_id = target.get("teacher_id")
    if linked_teacher_id and hasattr(db, "teachers"):
        linked_teacher = await db.teachers.find_one({"id": linked_teacher_id}, {"_id": 0})
    if not linked_teacher and email and hasattr(db, "teachers"):
        linked_teacher = await db.teachers.find_one({"email": email}, {"_id": 0})

    if linked_teacher:
        cleanup_result = await _cleanup_teacher_smoke_artifacts(
            linked_teacher,
            delete_user_emails=[email] if email else None,
        )
        deleted_counts.update(getattr(cleanup_result, "deleted_counts", {}) or {})
    else:
        if hasattr(db.users, "delete_one"):
            result = await db.users.delete_one({"id": user_id})
            deleted_counts["users"] = getattr(result, "deleted_count", 0)
        elif hasattr(db.users, "delete_many"):
            result = await db.users.delete_many({"id": user_id})
            deleted_counts["users"] = getattr(result, "deleted_count", 0)
        elif hasattr(db.users, "record"):
            if getattr(db.users, "record", None) and db.users.record.get("id") == user_id:
                db.users.record = None
                deleted_counts["users"] = 1
        else:
            docs = list(getattr(db.users, "docs", []))
            db.users.docs = [doc for doc in docs if doc.get("id") != user_id]
            deleted_counts["users"] = len(docs) - len(getattr(db.users, "docs", []))

    if hasattr(db, "user_sessions"):
        if hasattr(db.user_sessions, "delete_many"):
            result = await db.user_sessions.delete_many({"user_id": user_id})
            deleted_counts["user_sessions"] = getattr(result, "deleted_count", 0)
        else:
            before = len(getattr(db.user_sessions, "docs", []))
            db.user_sessions.docs = [doc for doc in getattr(db.user_sessions, "docs", []) if doc.get("user_id") != user_id]
            deleted_counts["user_sessions"] = before - len(getattr(db.user_sessions, "docs", []))

    if hasattr(db, "schools"):
        await db.schools.update_many(
            {"user_id": user_id},
            {"$set": {"user_id": None, "updated_at": datetime.now(timezone.utc).isoformat()}},
        )
    if hasattr(db, "teachers") and email:
        await db.teachers.update_many(
            {"manager_email": email},
            {"$set": {"manager_email": None, "manager_name": None}},
        )
    if hasattr(db, "users") and email:
        if hasattr(db.users, "update_many"):
            await db.users.update_many(
                {"manager_email": email},
                {"$set": {"manager_email": None, "manager_name": None}},
            )
        elif hasattr(db.users, "docs"):
            for index, doc in enumerate(list(db.users.docs)):
                if doc.get("manager_email") == email:
                    next_doc = dict(doc)
                    next_doc["manager_email"] = None
                    next_doc["manager_name"] = None
                    db.users.docs[index] = next_doc
    if hasattr(db, "organizations"):
        await db.organizations.update_many(
            {"created_by": user_id},
            {"$set": {"created_by": actor.get("email") or actor.get("id")}},
        )
        org_docs = await db.organizations.find({}, {"_id": 0, "id": 1}).to_list(1000)
        for org in org_docs:
            org_id = org.get("id")
            if not org_id:
                continue
            user_count = await db.users.count_documents({"organization_id": org_id})
            school_count = await db.schools.count_documents({"organization_id": org_id}) if hasattr(db, "schools") else 0
            if user_count == 0 and school_count == 0:
                result = await db.organizations.delete_one({"id": org_id})
                deleted_counts["organizations"] = deleted_counts.get("organizations", 0) + getattr(result, "deleted_count", 0)

    event_type = "approval_deleted" if _get_user_approval_status(target) == "pending" else "account_deleted"
    await _log_auth_event(
        event_type,
        email=email,
        user_id=user_id,
        result="success",
        reason=reason,
    )
    if event_type == "approval_deleted":
        try:
            from app.services.notification_service import NotificationService

            notification = await NotificationService().send_access_rejected(
                target,
                reason=reason,
                actor_label=actor.get("email") or actor.get("id"),
            )
            notification_payload = notification.get("payload") if isinstance(notification, dict) else {}
            deleted_snapshot["_email_delivery_attempted"] = True
            deleted_snapshot["_email_delivery_succeeded"] = bool(
                (notification_payload or {}).get("email_delivery_succeeded")
            )
        except Exception:
            logger.warning("Access rejection notification failed during hard delete", exc_info=True)
            deleted_snapshot["_email_delivery_attempted"] = True
            deleted_snapshot["_email_delivery_succeeded"] = False
    deleted_snapshot["deleted_counts"] = deleted_counts
    return deleted_snapshot


def _build_access_request_notification_message(user_doc: dict) -> EmailMessage:
    message = EmailMessage()
    message["Subject"] = f"Cognivio approval needed: {user_doc.get('email')}"
    message["From"] = SMTP_FROM_EMAIL
    message["To"] = ACCESS_APPROVAL_NOTIFY_EMAIL
    message.set_content(_build_access_request_notification_text(user_doc))
    return message


def _build_access_request_notification_text(user_doc: dict) -> str:
    approve_url = _build_access_request_action_url(user_doc, "approve")
    deny_url = _build_access_request_action_url(user_doc, "deny")
    tenant_summary = _build_tenant_request_summary(user_doc)
    tenant_lines = [
        f"Requested role: {tenant_summary.get('tenant_role_label')}",
        f"Institution type: {str(tenant_summary.get('organization_type') or '—').title()}",
        f"Organization: {tenant_summary.get('organization_name') or '—'}",
    ]
    if tenant_summary.get("school_name"):
        tenant_lines.append(f"School: {tenant_summary.get('school_name')}")
    if tenant_summary.get("manager_email"):
        tenant_lines.append(f"Requested {tenant_summary.get('manager_label')}: {tenant_summary.get('manager_email')}")
    return "\n".join(
        [
            "A new Cognivio pilot sign-up is waiting for approval.",
            "",
            f"Name: {user_doc.get('name')}",
            f"Email: {user_doc.get('email')}",
            *tenant_lines,
            f"Requested at: {user_doc.get('approval_requested_at') or user_doc.get('created_at')}",
            "",
            f"Approve now: {approve_url}",
            f"Deny now: {deny_url}",
            "",
            "You can also review this request from the Cognivio master-admin access approvals page after logging in.",
        ]
    )


