async def _app_startup() -> None:
    _validate_s3_config()
    await _ensure_database_indexes()
    await _ensure_master_admin_user()
    await _start_privacy_maintenance_tasks()
    await _start_video_transcode_workers()
    await _start_privacy_workers()
    await _start_video_workers()
    await _rehydrate_video_transcode_queue()
    await _rehydrate_video_privacy_queue()
    await _rehydrate_video_processing_queue()
    if not DEMO_MODE:
        return
    for demo in DEMO_USERS:
        existing = await db.users.find_one({"email": demo["email"]})
        desired_role = demo.get("role", "teacher")
        desired_tenant_role = demo.get("tenant_role") or ("school_admin" if desired_role == "admin" else "teacher")
        if existing:
            updates = {}
            if existing.get("role") != desired_role:
                updates["role"] = desired_role
            if existing.get("tenant_role") != desired_tenant_role:
                updates["tenant_role"] = desired_tenant_role
            if existing.get("tenant_status") != "approved":
                updates["tenant_status"] = "approved"
            if updates:
                await db.users.update_one({"email": demo["email"]}, {"$set": updates})
            continue
        user_id = str(uuid.uuid4())
        user_doc = {
            "id": user_id,
            "email": demo["email"],
            "name": demo["name"],
            "password": hash_password(demo["password"]),
            "created_at": datetime.now(timezone.utc).isoformat(),
            "is_demo": True,
            "role": desired_role,
            "tenant_role": desired_tenant_role,
            "tenant_status": "approved",
        }
        await db.users.insert_one(user_doc)
    await _ensure_demo_tenant_state()


async def _ensure_master_admin_user() -> None:
    if not MASTER_ADMIN_EMAIL or not MASTER_ADMIN_PASSWORD:
        return

    now = datetime.now(timezone.utc).isoformat()
    existing = await db.users.find_one({"email": MASTER_ADMIN_EMAIL})
    password_hash = hash_password(MASTER_ADMIN_PASSWORD)
    if existing:
        updates = {
            "name": MASTER_ADMIN_NAME,
            "password": password_hash,
            "role": "super_admin",
            "tenant_role": "super_admin",
            "tenant_status": "approved",
            "approval_status": "approved",
            "approved_at": existing.get("approved_at") or now,
            "approved_by": "system:master_admin_bootstrap",
            "approval_requested_at": existing.get("approval_requested_at") or now,
            "revoked_at": None,
            "revoked_by": None,
            "is_active": True,
            "updated_at": now,
        }
        await db.users.update_one({"email": MASTER_ADMIN_EMAIL}, {"$set": updates})
        return

    user_doc = {
        "id": str(uuid.uuid4()),
        "email": MASTER_ADMIN_EMAIL,
        "name": MASTER_ADMIN_NAME,
        "password": password_hash,
        "created_at": now,
        "role": "super_admin",
        "tenant_role": "super_admin",
        "tenant_status": "approved",
        "audio_analysis_enabled": True,
        "approval_status": "approved",
        "approval_requested_at": now,
        "approved_at": now,
        "approved_by": "system:master_admin_bootstrap",
        "is_active": True,
    }
    await db.users.insert_one(user_doc)


async def _app_shutdown() -> None:
    await _stop_video_workers()
    client.close()


@asynccontextmanager
async def lifespan(app: FastAPI):
    await _app_startup()
    try:
        yield
    finally:
        await _app_shutdown()


class UploadTooLargeError(Exception):
    pass


class InvalidVideoFileTypeError(Exception):
    pass


class UploadQuotaReachedError(Exception):
    pass


def _retry_after_from_rate_limit(exc: RateLimitExceeded) -> int:
    limit = getattr(exc, "limit", None)
    get_expiry = getattr(limit, "get_expiry", None)
    if callable(get_expiry):
        try:
            return max(1, int(math.ceil(float(get_expiry()))))
        except (TypeError, ValueError):
            pass
    return POST_RATE_LIMIT_WINDOW_SECONDS


async def _rate_limit_exceeded_handler(request: Request, exc: RateLimitExceeded) -> JSONResponse:
    retry_after = _retry_after_from_rate_limit(exc)
    return JSONResponse(
        status_code=429,
        content={"error": "Too many requests", "retry_after": retry_after},
        headers={"Retry-After": str(retry_after)},
    )


def _consume_post_rate_limit(request: Request) -> Optional[int]:
    path = request.url.path
    if request.method.upper() != "POST" or not path.startswith("/api/") or path in POST_RATE_LIMIT_EXEMPT_PATHS:
        return None
    now = time.monotonic()
    client_key = get_remote_address(request) or "unknown"
    bucket_key = (client_key, path)
    count, window_started_at = POST_RATE_LIMIT_BUCKETS.get(bucket_key, (0, now))
    elapsed = now - window_started_at
    if elapsed >= POST_RATE_LIMIT_WINDOW_SECONDS:
        POST_RATE_LIMIT_BUCKETS[bucket_key] = (1, now)
        return None
    if count >= POST_RATE_LIMIT_MAX_REQUESTS:
        return max(1, int(math.ceil(POST_RATE_LIMIT_WINDOW_SECONDS - elapsed)))
    POST_RATE_LIMIT_BUCKETS[bucket_key] = (count + 1, window_started_at)
    return None


# Create the main app
app = FastAPI(
    title="Cognivio API",
    description="Teacher Assessment Platform",
    lifespan=lifespan,
)
app.state.limiter = limiter
app.add_exception_handler(RateLimitExceeded, _rate_limit_exceeded_handler)


@app.exception_handler(UploadTooLargeError)
async def upload_too_large_handler(request: Request, exc: UploadTooLargeError):
    return JSONResponse(
        status_code=413,
        content={"error": "File too large", "max_bytes": VIDEO_MAX_UPLOAD_BYTES},
    )


@app.exception_handler(InvalidVideoFileTypeError)
async def invalid_video_file_type_handler(request: Request, exc: InvalidVideoFileTypeError):
    return JSONResponse(
        status_code=422,
        content={"error": "Invalid file type", "allowed": VIDEO_ALLOWED_FILE_TYPES},
    )


@app.exception_handler(UploadQuotaReachedError)
async def upload_quota_reached_handler(request: Request, exc: UploadQuotaReachedError):
    return JSONResponse(
        status_code=402,
        content={"error": "Upload quota reached", "contact": "support@cognivio.com"},
    )


@app.middleware("http")
async def reject_oversized_video_uploads(request: Request, call_next):
    if request.method.upper() == "POST" and request.url.path == "/api/videos/upload":
        content_length = request.headers.get("content-length")
        if content_length:
            try:
                if int(content_length) > VIDEO_MAX_UPLOAD_BYTES:
                    return JSONResponse(
                        status_code=413,
                        content={"error": "File too large", "max_bytes": VIDEO_MAX_UPLOAD_BYTES},
                    )
            except ValueError:
                pass
    return await call_next(request)


@app.middleware("http")
async def enforce_general_post_rate_limit(request: Request, call_next):
    retry_after = _consume_post_rate_limit(request)
    if retry_after is not None:
        return JSONResponse(
            status_code=429,
            content={"error": "Too many requests", "retry_after": retry_after},
            headers={"Retry-After": str(retry_after)},
        )
    return await call_next(request)


@app.middleware("http")
async def block_write_requests_in_preview_mode(request: Request, call_next):
    preview_target_id = str(request.headers.get("X-Cognivio-Preview-User") or "").strip()
    if (
        preview_target_id
        and request.url.path.startswith("/api")
        and request.method.upper() not in {"GET", "HEAD", "OPTIONS"}
    ):
        return JSONResponse(
            status_code=403,
            content={"detail": "Preview mode is read-only. Exit preview mode before making changes."},
        )
    return await call_next(request)


CSRF_EXEMPT_PATHS = {
    "/api/auth/login",
    "/api/auth/register",
    "/api/auth/request-access",
    "/api/auth/logout",
    "/api/auth/password-reset/request",
    "/api/auth/password-reset/confirm",
}


@app.middleware("http")
async def enforce_csrf_for_session_auth(request: Request, call_next):
    method = request.method.upper()
    path = request.url.path
    if (
        method in {"POST", "PUT", "PATCH", "DELETE"}
        and path.startswith("/api/")
        and path not in CSRF_EXEMPT_PATHS
    ):
        if request.cookies.get(SESSION_COOKIE_NAME):
            if not _csrf_is_valid(request):
                return JSONResponse(status_code=403, content={"detail": "CSRF token validation failed"})
    return await call_next(request)

# Health check endpoint (at root level for Railway)
@app.get("/health")
async def health_check():
    """Health check endpoint for Railway deployment"""
    return _build_public_health_payload()

@api_router.get("/health")
async def api_health_check():
    """Health check endpoint under /api prefix"""
    return _build_public_health_payload()

@api_router.get("/health/version")
async def api_health_version():
    """Safe deployment/version metadata for frontend and manual deployment checks."""
    return _build_public_health_payload()

def _build_public_health_payload() -> dict:
    commit = (
        os.getenv("RAILWAY_GIT_COMMIT_SHA")
        or os.getenv("RENDER_GIT_COMMIT")
        or os.getenv("GIT_COMMIT")
        or os.getenv("COMMIT_SHA")
        or ""
    )
    build_id = (
        os.getenv("RAILWAY_DEPLOYMENT_ID")
        or os.getenv("CF_PAGES_COMMIT_SHA")
        or os.getenv("BUILD_ID")
        or ""
    )
    return {
        "status": "healthy",
        "ok": True,
        "service": "cognivio-api",
        "environment": APP_SETTINGS.environment,
        "railway_environment_name": os.getenv("RAILWAY_ENVIRONMENT_NAME") or None,
        "commit_sha": commit[:40] or None,
        "build_id": build_id[:80] or None,
        "build": {
            "commit": commit[:40] or None,
            "id": build_id[:80] or None,
            "version": os.getenv("APP_VERSION") or None,
            "deployed_at": os.getenv("RAILWAY_DEPLOYMENT_CREATED_AT") or None,
        },
        "frontend_url_configured": bool(FRONTEND_URL),
        "backend_public_base_url_configured": bool(BACKEND_PUBLIC_BASE_URL),
        "server_time": datetime.now(timezone.utc).isoformat(),
    }


def _upload_storage_is_healthy() -> bool:
    if S3_BUCKET:
        try:
            return _probe_s3_bucket_health()
        except Exception:
            return False
    try:
        UPLOAD_DIR.mkdir(parents=True, exist_ok=True)
        probe_file = UPLOAD_DIR / ".metrics-write-check"
        probe_file.write_text("ok", encoding="utf-8")
        probe_file.unlink(missing_ok=True)
        return True
    except Exception:
        return False


async def refresh_runtime_metrics() -> None:
    cutoff_stale = (datetime.now(timezone.utc) - timedelta(minutes=45)).isoformat()

    video_processing = await db.video_processing_jobs.count_documents(
        {"status": VideoProcessingStatus.PROCESSING.value}
    )
    video_stuck = await db.video_processing_jobs.count_documents(
        {
            "status": VideoProcessingStatus.PROCESSING.value,
            "started_at": {"$lte": cutoff_stale},
        }
    )
    privacy_processing = await db.video_privacy_jobs.count_documents(
        {"status": PrivacyProcessingStatus.PROCESSING.value}
    )
    privacy_stuck = await db.video_privacy_jobs.count_documents(
        {
            "status": PrivacyProcessingStatus.PROCESSING.value,
            "started_at": {"$lte": cutoff_stale},
        }
    )
    maintenance_processing = sum(1 for task in PRIVACY_MAINTENANCE_TASKS if not task.done())

    app_metrics.set_job_backlog(
        job_type="video",
        queued=VIDEO_JOB_QUEUE.qsize(),
        processing=video_processing,
        stuck=video_stuck,
    )
    app_metrics.set_job_backlog(
        job_type="privacy",
        queued=VIDEO_PRIVACY_JOB_QUEUE.qsize(),
        processing=privacy_processing,
        stuck=privacy_stuck,
    )
    app_metrics.set_job_backlog(
        job_type="maintenance",
        queued=0,
        processing=maintenance_processing,
        stuck=0,
    )

    mongo_healthy = True
    try:
        await db.command("ping")
    except Exception:
        mongo_healthy = False

    app_metrics.set_dependency_health(dependency="mongodb", healthy=mongo_healthy)
    app_metrics.set_dependency_health(
        dependency="openai",
        healthy=bool(OPENAI_API_KEY and AsyncOpenAI is not None),
    )
    app_metrics.set_dependency_health(
        dependency="storage",
        healthy=_upload_storage_is_healthy(),
    )
    app_metrics.set_dependency_health(
        dependency="railway_runtime",
        healthy=True,
    )

