async def _purge_expired_privacy_artifacts() -> None:
    now_iso = datetime.now(timezone.utc).isoformat()

    expired_refs = await db.teacher_face_references.find(
        {"retention_expires_at": {"$ne": None, "$lte": now_iso}},
        {"_id": 0},
    ).to_list(500)
    for ref in expired_refs:
        file_path = ref.get("file_path")
        if file_path:
            try:
                full_path = UPLOAD_DIR / str(file_path)
                if full_path.exists():
                    await asyncio.to_thread(os.remove, full_path)
            except Exception as exc:
                logger.warning(f"Failed to remove expired privacy reference {ref.get('id')}: {exc}")
        _delete_s3_key(ref.get("s3_key"))
        await db.teacher_face_references.update_one(
            {"id": ref["id"]},
            {
                "$set": {
                    "file_path": None,
                    "file_url": None,
                    "s3_key": None,
                    "purged_at": now_iso,
                }
            },
        )
        await _log_privacy_audit_event(
            "privacy_reference_purged",
            "teacher_reference",
            ref["id"],
            details={"teacher_id": ref.get("teacher_id")},
        )

    expired_videos = await db.videos.find(
        {
            "raw_retention_expires_at": {"$ne": None, "$lte": now_iso},
            "privacy_status": {"$in": [PrivacyProcessingStatus.COMPLETED.value, PrivacyProcessingStatus.FAILED.value]},
        },
        {"_id": 0},
    ).to_list(500)
    for video in expired_videos:
        raw_path = video.get("raw_file_path")
        if raw_path:
            try:
                full_path = UPLOAD_DIR / str(raw_path)
                if full_path.exists():
                    await asyncio.to_thread(os.remove, full_path)
            except Exception as exc:
                logger.warning(f"Failed to remove expired raw video {video.get('id')}: {exc}")
        _delete_s3_key(video.get("raw_s3_key") or video.get("s3_key"))
        await db.videos.update_one(
            {"id": video["id"]},
            {
                "$set": {
                    "raw_file_path": None,
                    "raw_file_url": None,
                    "raw_s3_key": None,
                    "raw_purged_at": now_iso,
                }
            },
        )
        await _log_privacy_audit_event(
            "raw_video_purged",
            "video",
            video["id"],
            details={"teacher_id": video.get("teacher_id")},
        )

    expired_transcripts = await db.video_audio_transcripts.find(
        {"retention_expires_at": {"$ne": None, "$lte": now_iso}},
        {"_id": 0, "id": 1, "video_id": 1},
    ).to_list(500)
    for transcript in expired_transcripts:
        await db.video_audio_transcripts.delete_one({"id": transcript["id"]})
        await _log_privacy_audit_event(
            "audio_transcript_purged",
            "video_audio_transcript",
            transcript["id"],
            details={"video_id": transcript.get("video_id")},
        )


async def _privacy_maintenance_worker() -> None:
    logger.info("Privacy maintenance worker started")
    try:
        while True:
            try:
                await _purge_expired_privacy_artifacts()
            except Exception as exc:
                logger.error(f"Privacy maintenance worker failed: {exc}")
            await asyncio.sleep(PRIVACY_PURGE_INTERVAL_MINUTES * 60)
    except asyncio.CancelledError:
        logger.info("Privacy maintenance worker stopped")
        raise


async def _start_privacy_maintenance_tasks() -> None:
    if PRIVACY_MAINTENANCE_TASKS:
        return
    task = asyncio.create_task(_privacy_maintenance_worker(), name="privacy-maintenance-worker")
    PRIVACY_MAINTENANCE_TASKS.append(task)


async def upload_video(
    request: Request,
    file: UploadFile = File(...),
    teacher_id: Optional[str] = Form(None),
    subject: Optional[str] = Form(None),
    lesson_title: Optional[str] = Form(None),
    class_section: Optional[str] = Form(None),
    recorded_at: Optional[str] = Form(None),
    observation_session_id: Optional[str] = Form(None),
    current_user: dict = Depends(get_current_user)
):
    preferred_language = _resolve_request_language(request, default="en")
    upload_started_perf = time.perf_counter()
    try:
        upload_source = _get_user_role(current_user)
        if not isinstance(observation_session_id, str) or not observation_session_id.strip():
            observation_session_id = None
        else:
            observation_session_id = observation_session_id.strip()
        detected_video = await _validate_video_upload_file(file)
        file_ext = detected_video["extension"]
        content_type = detected_video["content_type"]
        normalized_recorded_at = _parse_optional_iso_datetime(recorded_at, "recorded_at")
        upload_time = datetime.now(timezone.utc).isoformat()

        if not teacher_id and _get_user_tenant_role(current_user) == "teacher":
            teacher = await _get_current_teacher_for_workspace(current_user)
            teacher_id = teacher["id"]
        elif not teacher_id:
            raise HTTPException(status_code=400, detail="Teacher is required for admin uploads")
        else:
            teacher = await _get_teacher_or_404(teacher_id, current_user)
        observation_session = None
        if observation_session_id:
            observation_session = await _get_observation_session_or_404(observation_session_id, current_user)
            if observation_session.get("teacher_id") != teacher_id:
                raise HTTPException(
                    status_code=400,
                    detail="Observation session must belong to the selected teacher",
                )
        await _ensure_workspace_upload_quota_available(teacher, current_user)
        active_profile = await _get_active_privacy_profile(teacher_id)
        if PRIVACY_REQUIRE_PROFILE and not active_profile:
            raise HTTPException(
                status_code=409,
                detail={
                    "code": "PRIVACY_PROFILE_REQUIRED",
                    "message": "Teacher privacy profile must be completed before video upload.",
                    "teacher_id": teacher_id,
                },
            )

        subject = subject or teacher.get("subject")
        lesson_title = _clean_optional_string(lesson_title) or file.filename or subject
        class_section = _clean_optional_string(class_section) or teacher.get("class_section") or teacher.get("department")
        reference_images = await get_teacher_reference_images_for_blur(teacher_id, _workspace_id_for_user(current_user))
        reference_count = len(reference_images)
        reference_status = "ready" if reference_count else "missing_reference_images"
        video_id = str(uuid.uuid4())
        filename = f"{video_id}{file_ext}"
        teacher_dir = UPLOAD_DIR / "videos" / teacher_id
        teacher_dir.mkdir(parents=True, exist_ok=True)
        file_path = teacher_dir / filename
        relative_path = f"videos/{teacher_id}/{filename}"

        size = 0
        async with aiofiles.open(file_path, "wb") as f:
            while True:
                chunk = await file.read(1024 * 1024)
                if not chunk:
                    break
                size += len(chunk)
                if VIDEO_MAX_UPLOAD_BYTES and size > VIDEO_MAX_UPLOAD_BYTES:
                    await f.close()
                    os.remove(file_path)
                    raise UploadTooLargeError()
                await f.write(chunk)

        s3_key = None
        file_url = None
        try:
            raw_s3_key_override = _build_video_asset_s3_key("raw", teacher_id, filename)
            s3_key, file_url = _upload_path_to_s3(
                file_path,
                "videos",
                filename,
                content_type,
                key_override=raw_s3_key_override,
            )
        except Exception as exc:
            logger.warning(f"S3 upload failed for video {video_id}: {exc}")

        transcode_status = (
            VideoTranscodeStatus.QUEUED.value
            if VIDEO_TRANSCODE_PIPELINE_ENABLED
            else VideoTranscodeStatus.NOT_REQUIRED.value
        )

        video_doc = {
            "id": video_id,
            "filename": file.filename,
            "stored_filename": filename,
            "s3_key": s3_key,
            "raw_s3_key": s3_key,
            "file_url": file_url,
            "raw_file_url": file_url,
            "file_path": relative_path,
            "raw_file_path": relative_path,
            "content_type": content_type,
            "file_size_bytes": size,
            "raw_file_size_bytes": size,
            "processed_s3_key": None,
            "processed_file_url": None,
            "processed_file_path": None,
            "processed_content_type": None,
            "processed_file_size_bytes": None,
            "teacher_id": teacher_id,
            "observation_session_id": observation_session_id or None,
            "uploaded_by": current_user["id"],
            "status": VideoProcessingStatus.QUEUED.value,
            "privacy_status": PrivacyProcessingStatus.QUEUED.value,
            "analysis_status": VideoProcessingStatus.QUEUED.value,
            "transcode_status": transcode_status,
            "transcode_started_at": None,
            "transcode_completed_at": None,
            "transcode_failed_at": None,
            "transcode_error": None,
            "transcode_profile": VIDEO_TRANSCODE_PROFILE,
            "processing_asset_preference": "raw",
            "privacy_review_required": False,
            "privacy_review_reason": None,
            "privacy_started_at": None,
            "privacy_completed_at": None,
            "privacy_failed_at": None,
            "privacy_error": None,
            "privacy_profile_version": active_profile.get("profile_version") if active_profile else None,
            "raw_retention_expires_at": (datetime.now(timezone.utc) + timedelta(days=PRIVACY_RAW_VIDEO_RETENTION_DAYS)).isoformat(),
            "status_updated_at": upload_time,
            "processing_started_at": None,
            "processing_completed_at": None,
            "processing_failed_at": None,
            "subject": subject,
            "lesson_title": lesson_title,
            "class_section": class_section,
            "recorded_at": normalized_recorded_at,
            "upload_date": upload_time,
            "analysis_language": preferred_language,
            "teacher_reference_images_available": reference_count > 0,
            "teacher_reference_image_count": reference_count,
            "privacy_blur_teacher_match_status": reference_status,
        }
        await db.videos.insert_one(video_doc)

        if VIDEO_TRANSCODE_PIPELINE_ENABLED:
            await _enqueue_video_transcode_job(
                video_id=video_id,
                teacher_id=teacher_id,
                user_id=current_user["id"],
                file_path=str(file_path),
                source_content_type=content_type,
                raw_s3_key=s3_key,
                raw_file_url=file_url,
                requested_profile=VIDEO_TRANSCODE_PROFILE,
            )

        await db.video_evidence.insert_one({
            "id": str(uuid.uuid4()),
            "video_id": video_id,
            "teacher_id": teacher_id,
            "observation_session_id": observation_session_id or None,
            "file_path": relative_path,
            "subject": subject,
            "lesson_title": lesson_title,
            "class_section": class_section,
            "recorded_at": normalized_recorded_at,
            "privacy_status": PrivacyProcessingStatus.QUEUED.value,
            "analysis_status": VideoProcessingStatus.QUEUED.value,
            "uploaded_by": current_user["id"],
            "uploaded_at": upload_time,
            "teacher_reference_images_available": reference_count > 0,
            "teacher_reference_image_count": reference_count,
            "privacy_blur_teacher_match_status": reference_status,
        })

        if observation_session:
            await db.observation_sessions.update_one(
                {"id": observation_session["id"]},
                {
                    "$set": {
                        "linked_video_id": video_id,
                        "status": ObservationSessionStatus.RECORDING_UPLOADED.value,
                        "updated_at": upload_time,
                    }
                },
            )

        try:
            admin_id = teacher.get("created_by") or current_user["id"]
            policy = await _get_recording_policy(admin_id, teacher.get("school_id"))
            if policy:
                compliance = await _upsert_recording_compliance(teacher, admin_id, policy)
                await _refresh_recording_reminders(teacher, admin_id, policy, compliance)
        except Exception:
            logger.warning("Unable to update recording compliance after upload")

        if not VIDEO_TRANSCODE_PIPELINE_ENABLED:
            await _enqueue_video_privacy_job(
                video_id=video_id,
                teacher_id=teacher_id,
                user_id=current_user["id"],
                file_path=str(file_path),
            )
        await _log_privacy_audit_event(
            "privacy_video_uploaded",
            "video",
            video_id,
            actor_user_id=current_user["id"],
            details={
                "teacher_id": teacher_id,
                "privacy_status": PrivacyProcessingStatus.QUEUED.value,
                "raw_retention_expires_at": video_doc["raw_retention_expires_at"],
            },
        )
        duration_seconds = time.perf_counter() - upload_started_perf
        app_metrics.record_upload_result(
            source=upload_source,
            language=preferred_language,
            success=True,
            duration_seconds=duration_seconds,
        )

        return VideoUploadResponse(
            id=video_id,
            filename=file.filename,
            teacher_id=teacher_id,
            observation_session_id=observation_session_id or None,
            status=VideoProcessingStatus.QUEUED.value,
            privacy_status=PrivacyProcessingStatus.QUEUED.value,
            analysis_status=VideoProcessingStatus.QUEUED.value,
            transcode_status=transcode_status,
            upload_date=video_doc["upload_date"],
            subject=subject,
            lesson_title=lesson_title,
            class_section=class_section,
            recorded_at=normalized_recorded_at,
            file_path=relative_path,
            file_size_bytes=size,
            content_type=content_type,
            teacher_reference_images_available=reference_count > 0,
            teacher_reference_image_count=reference_count,
            privacy_blur_teacher_match_status=reference_status,
        )
    except HTTPException:
        app_metrics.record_upload_result(
            source=_get_user_role(current_user),
            language=preferred_language,
            success=False,
            duration_seconds=time.perf_counter() - upload_started_perf,
        )
        raise
    except Exception:
        app_metrics.record_upload_result(
            source=_get_user_role(current_user),
            language=preferred_language,
            success=False,
            duration_seconds=time.perf_counter() - upload_started_perf,
        )
        raise


async def get_videos(teacher_id: Optional[str] = None, current_user: dict = Depends(get_current_user)):
    query: Dict[str, Any] = {}
    if teacher_id:
        await _get_teacher_or_404(teacher_id, current_user)
        query["teacher_id"] = teacher_id
    else:
        teacher_ids_for_user = await _list_teacher_ids_for_user(current_user)
        query = _build_video_visibility_query(current_user, teacher_ids_for_user)
    videos = await db.videos.find(query, {"_id": 0, "uploaded_by": 0, "stored_filename": 0}).to_list(1000)
    for video in videos:
        _apply_video_response_defaults(video)
    return [_sanitize_video_response(video) for video in videos]


async def get_video_detail(video_id: str, current_user: dict = Depends(get_current_user)):
    """Get full video metadata including stored filename for playback."""
    video = await db.videos.find_one({"id": video_id}, {"_id": 0})
    if not video:
        raise HTTPException(status_code=404, detail="Video not found")
    await _get_teacher_or_404(video.get("teacher_id"), current_user)
    return _sanitize_video_response(_apply_video_response_defaults(video))


async def get_video_raw_access(video_id: str, current_user: dict = Depends(get_current_user)):
    role = _get_user_role(current_user)
    if role != "admin":
        raise HTTPException(status_code=403, detail="Admin access required")
    video = await db.videos.find_one({"id": video_id}, {"_id": 0})
    if not video:
        raise HTTPException(status_code=404, detail="Video not found")
    await _get_teacher_or_404(video.get("teacher_id"), current_user)
    raw_url = video.get("raw_file_url")
    raw_path = video.get("raw_file_path")
    access_url = raw_url
    if not access_url and raw_path:
        safe_path = str(raw_path).replace("\\", "/").lstrip("/")
        access_url = _to_public_backend_url(f"/uploads/{safe_path}")
    if not access_url:
        raise HTTPException(status_code=404, detail="Raw asset is no longer available")
    await _log_privacy_audit_event(
        "raw_asset_accessed",
        "video",
        video_id,
        actor_user_id=current_user["id"],
        details={"reason": "admin_raw_access_endpoint"},
    )
    return {
        "video_id": video_id,
        "access_url": access_url,
        "expires_at": None,
        "retention_expires_at": video.get("raw_retention_expires_at"),
    }

async def get_video_status(video_id: str, current_user: dict = Depends(get_current_user)):
    video = await db.videos.find_one({"id": video_id}, {"_id": 0})
    if not video:
        raise HTTPException(status_code=404, detail="Video not found")
    await _get_teacher_or_404(video.get("teacher_id"), current_user)
    return {
        "status": _normalize_video_status(video.get("status")),
        "privacy_status": _normalize_privacy_status(video.get("privacy_status")),
        "analysis_status": _normalize_video_status(video.get("analysis_status")),
        "transcode_status": _normalize_video_transcode_status(video.get("transcode_status")),
        "privacy_review_required": bool(video.get("privacy_review_required", False)),
        "privacy_review_reason": video.get("privacy_review_reason"),
        "error_message": video.get("error_message"),
        "privacy_error": video.get("privacy_error"),
    }


async def _resolve_video_comment_rubric_fields(
    video_id: str,
    element_id: Optional[str],
    element_code: Optional[str],
    element_name: Optional[str],
) -> Dict[str, Optional[str]]:
    cleaned_element_id = _clean_optional_string(element_id)
    cleaned_code = _clean_optional_string(element_code) or cleaned_element_id
    cleaned_name = _clean_optional_string(element_name)
    if cleaned_element_id and not cleaned_name:
        assessment = await db.assessments.find_one(
            {"video_id": video_id},
            {"_id": 0, "element_scores": 1},
        )
        for score in assessment.get("element_scores", []) if assessment else []:
            if score.get("element_id") == cleaned_element_id:
                cleaned_name = _clean_optional_string(score.get("element_name"))
                cleaned_code = cleaned_code or _clean_optional_string(score.get("element_id"))
                break
    return {
        "rubric_element_id": cleaned_element_id,
        "rubric_element_code": cleaned_code,
        "rubric_element_name": cleaned_name,
    }


@api_router.get("/videos/{video_id}/comments", response_model=VideoCommentListResponse)
async def list_video_comments(
    video_id: str,
    current_user: dict = Depends(get_current_user),
):
    await _get_visible_video_or_404(video_id, current_user)
    docs = await db.video_comments.find(
        _comment_visibility_query(video_id, current_user),
        {"_id": 0},
    ).sort("timestamp_seconds", 1).to_list(1000)
    docs.sort(
        key=lambda item: (
            float(item.get("timestamp_seconds") or 0),
            str(item.get("created_at") or ""),
        )
    )
    return VideoCommentListResponse(
        comments=[VideoComment(**_sanitize_video_comment_doc(doc)) for doc in docs]
    )


@api_router.post("/videos/{video_id}/comments", response_model=VideoComment)
async def create_video_comment(
    video_id: str,
    payload: VideoCommentCreate,
    current_user: dict = Depends(get_current_user),
):
    video = await _get_visible_video_or_404(video_id, current_user)
    teacher = await db.teachers.find_one({"id": video.get("teacher_id")}, {"_id": 0})
    body = (payload.body or "").strip()
    if not body:
        raise HTTPException(status_code=400, detail="Comment text is required")
    if len(body) > 4000:
        raise HTTPException(status_code=400, detail="Comment text is too long")
    timestamp_seconds = float(payload.timestamp_seconds or 0)
    if timestamp_seconds < 0:
        raise HTTPException(status_code=400, detail="Comment timestamp cannot be negative")
    visibility = _normalize_video_comment_visibility(payload.visibility, payload.is_private)
    tenant_role = _get_user_tenant_role(current_user)
    if tenant_role == "teacher" and visibility != "shared_with_teacher":
        raise HTTPException(status_code=403, detail="Teachers can only add shared lesson comments")
    if visibility == "admin_only" and not _video_comment_is_admin_role(current_user):
        raise HTTPException(status_code=403, detail="Admin access required for admin-only comments")
    thread_parent_id = _clean_optional_string(payload.thread_parent_id)
    if thread_parent_id:
        parent = await _get_video_comment_or_404(video_id, thread_parent_id, current_user)
        if parent.get("thread_parent_id"):
            raise HTTPException(status_code=400, detail="Replies can only be one level deep")
        timestamp_seconds = float(parent.get("timestamp_seconds") or timestamp_seconds)
    rubric_fields = await _resolve_video_comment_rubric_fields(
        video_id,
        payload.rubric_element_id,
        payload.rubric_element_code,
        payload.rubric_element_name,
    )
    now = datetime.now(timezone.utc).isoformat()
    doc = {
        "id": str(uuid.uuid4()),
        "video_id": video_id,
        "workspace_id": _resolve_video_workspace_id(video, teacher, current_user),
        "organization_id": video.get("organization_id") or (teacher or {}).get("organization_id"),
        "teacher_id": video.get("teacher_id"),
        "observation_session_id": video.get("observation_session_id") or video.get("session_id"),
        "author_id": current_user["id"],
        "author_name": (
            _clean_optional_string(current_user.get("name"))
            or _clean_optional_string(current_user.get("email"))
            or "Cognivio user"
        ),
        "author_role": _get_user_tenant_role(current_user),
        "timestamp_seconds": timestamp_seconds,
        "focus_area_id": _clean_optional_string(payload.focus_area_id) or rubric_fields.get("rubric_element_id"),
        "focus_area_label": _clean_optional_string(payload.focus_area_label) or rubric_fields.get("rubric_element_name") or rubric_fields.get("rubric_element_code"),
        "visibility": visibility,
        **rubric_fields,
        "body": body,
        "is_private": visibility == "observer_private",
        "thread_parent_id": thread_parent_id,
        "created_at": now,
        "updated_at": now,
    }
    await db.video_comments.insert_one(doc)
    return VideoComment(**_sanitize_video_comment_doc(doc))


@api_router.patch("/videos/{video_id}/comments/{comment_id}", response_model=VideoComment)
async def update_video_comment(
    video_id: str,
    comment_id: str,
    payload: VideoCommentUpdate,
    current_user: dict = Depends(get_current_user),
):
    await _get_visible_video_or_404(video_id, current_user)
    comment = await _get_video_comment_or_404(video_id, comment_id, current_user)
    if not _video_comment_can_manage(comment, current_user):
        raise HTTPException(status_code=403, detail="Only the author or an admin can edit this comment")
    created_at = _parse_comment_created_at(comment.get("created_at"))
    if comment.get("author_id") == current_user["id"] and datetime.now(timezone.utc) - created_at > timedelta(minutes=15):
        raise HTTPException(status_code=403, detail="Comments can only be edited within 15 minutes")
    updates = payload.dict(exclude_unset=True)
    update_fields: Dict[str, Any] = {}
    if "body" in updates:
        body = (payload.body or "").strip()
        if not body:
            raise HTTPException(status_code=400, detail="Comment text is required")
        if len(body) > 4000:
            raise HTTPException(status_code=400, detail="Comment text is too long")
        update_fields["body"] = body
    if "is_private" in updates and payload.is_private is not None:
        update_fields["visibility"] = _normalize_video_comment_visibility(None, bool(payload.is_private))
        update_fields["is_private"] = update_fields["visibility"] == "observer_private"
    if "visibility" in updates and payload.visibility is not None:
        visibility = _normalize_video_comment_visibility(payload.visibility)
        if _get_user_tenant_role(current_user) == "teacher" and visibility != "shared_with_teacher":
            raise HTTPException(status_code=403, detail="Teachers can only add shared lesson comments")
        if visibility == "admin_only" and not _video_comment_is_admin_role(current_user):
            raise HTTPException(status_code=403, detail="Admin access required for admin-only comments")
        update_fields["visibility"] = visibility
        update_fields["is_private"] = visibility == "observer_private"
    if "focus_area_id" in updates:
        update_fields["focus_area_id"] = _clean_optional_string(payload.focus_area_id)
    if "focus_area_label" in updates:
        update_fields["focus_area_label"] = _clean_optional_string(payload.focus_area_label)
    rubric_keys = {"rubric_element_id", "rubric_element_code", "rubric_element_name"}
    if rubric_keys.intersection(updates.keys()):
        rubric_fields = await _resolve_video_comment_rubric_fields(
            video_id,
            payload.rubric_element_id,
            payload.rubric_element_code,
            payload.rubric_element_name,
        )
        update_fields.update(rubric_fields)
        update_fields.setdefault("focus_area_id", rubric_fields.get("rubric_element_id"))
        update_fields.setdefault("focus_area_label", rubric_fields.get("rubric_element_name") or rubric_fields.get("rubric_element_code"))
    if not update_fields:
        raise HTTPException(status_code=400, detail="No fields to update")
    update_fields["updated_at"] = datetime.now(timezone.utc).isoformat()
    update_fields["edited_at"] = update_fields["updated_at"]
    updated = await db.video_comments.find_one_and_update(
        {"id": comment_id, "video_id": video_id},
        {"$set": update_fields},
        projection={"_id": 0},
        return_document=True,
    )
    if not updated:
        raise HTTPException(status_code=404, detail="Comment not found")
    return VideoComment(**_sanitize_video_comment_doc(updated))


@api_router.delete("/videos/{video_id}/comments/{comment_id}")
async def delete_video_comment(
    video_id: str,
    comment_id: str,
    current_user: dict = Depends(get_current_user),
):
    await _get_visible_video_or_404(video_id, current_user)
    comment = await _get_video_comment_or_404(video_id, comment_id, current_user)
    if not _video_comment_can_manage(comment, current_user):
        raise HTTPException(status_code=403, detail="Only the author or an admin can delete this comment")
    if comment.get("is_private") and comment.get("author_id") != current_user["id"]:
        raise HTTPException(status_code=403, detail="Only the author can delete a private comment")
    now = datetime.now(timezone.utc).isoformat()
    if comment.get("thread_parent_id"):
        result = await db.video_comments.update_one(
            {"id": comment_id, "video_id": video_id},
            {"$set": {"deleted_at": now, "updated_at": now}},
        )
        deleted_count = getattr(result, "modified_count", 0) or getattr(result, "matched_count", 0)
    else:
        result = await db.video_comments.update_many(
            {
                "video_id": video_id,
                "$or": [{"id": comment_id}, {"thread_parent_id": comment_id}],
            },
            {"$set": {"deleted_at": now, "updated_at": now}},
        )
        deleted_count = getattr(result, "modified_count", 0) or getattr(result, "matched_count", 0)
    if deleted_count == 0:
        raise HTTPException(status_code=404, detail="Comment not found")
    return {"message": "Comment deleted", "deleted_count": deleted_count}


async def retry_video_processing(video_id: str, current_user: dict = Depends(get_current_user)):
    video = await db.videos.find_one({"id": video_id}, {"_id": 0})
    if not video:
        raise HTTPException(status_code=404, detail="Video not found")
    await _get_teacher_or_404(video.get("teacher_id"), current_user)
    current_status = _normalize_video_status(video.get("status"))
    if current_status != VideoProcessingStatus.FAILED.value:
        raise HTTPException(status_code=400, detail="Only failed videos can be retried")
    if _normalize_privacy_status(video.get("privacy_status")) != PrivacyProcessingStatus.COMPLETED.value:
        raise HTTPException(status_code=409, detail="Retry unavailable until privacy processing is complete")
    relative_path = video.get("redacted_file_path") or video.get("file_path")
    if not relative_path:
        raise HTTPException(status_code=409, detail="Retry unavailable for videos without local source")
    full_path = UPLOAD_DIR / str(relative_path)
    if not full_path.exists():
        raise HTTPException(status_code=409, detail="Retry unavailable because the local video file is missing")
    queued_at = datetime.now(timezone.utc).isoformat()
    await db.videos.update_one(
        {"id": video_id},
        {
            "$set": {
                "status": VideoProcessingStatus.QUEUED.value,
                "analysis_status": VideoProcessingStatus.QUEUED.value,
                "status_updated_at": queued_at,
                "error_message": None,
            }
        },
    )
    await db.video_evidence.update_one(
        {"video_id": video_id},
        {"$set": {"analysis_status": VideoProcessingStatus.QUEUED.value, "error_message": None}},
    )
    await _enqueue_video_processing_job(
        video_id=video_id,
        teacher_id=video.get("teacher_id"),
        user_id=video.get("uploaded_by") or current_user["id"],
        file_path=str(full_path),
    )
    return {"video_id": video_id, "status": VideoProcessingStatus.QUEUED.value}


async def retry_video_privacy(video_id: str, current_user: dict = Depends(get_current_user)):
    video = await db.videos.find_one({"id": video_id}, {"_id": 0})
    if not video:
        raise HTTPException(status_code=404, detail="Video not found")
    await _get_teacher_or_404(video.get("teacher_id"), current_user)
    relative_path = (
        video.get("processed_file_path")
        or video.get("raw_file_path")
        or video.get("file_path")
    )
    if not relative_path:
        raise HTTPException(status_code=409, detail="Retry unavailable for videos without local source")
    full_path = UPLOAD_DIR / str(relative_path)
    if not full_path.exists():
        raise HTTPException(status_code=409, detail="Retry unavailable because the local video file is missing")
    queued_at = datetime.now(timezone.utc).isoformat()
    await db.videos.update_one(
        {"id": video_id},
        {
            "$set": {
                "status": VideoProcessingStatus.QUEUED.value,
                "privacy_status": PrivacyProcessingStatus.QUEUED.value,
                "analysis_status": VideoProcessingStatus.QUEUED.value,
                "privacy_review_required": False,
                "privacy_review_reason": None,
                "privacy_error": None,
                "privacy_started_at": None,
                "privacy_completed_at": None,
                "privacy_failed_at": None,
                "status_updated_at": queued_at,
            }
        },
    )
    await _enqueue_video_privacy_job(
        video_id=video_id,
        teacher_id=video.get("teacher_id"),
        user_id=video.get("uploaded_by") or current_user["id"],
        file_path=str(full_path),
    )
    await _log_privacy_audit_event(
        "privacy_retry_queued",
        "video",
        video_id,
        actor_user_id=current_user["id"],
        details={"requeued_at": queued_at},
    )
    return {
        "video_id": video_id,
        "privacy_status": PrivacyProcessingStatus.QUEUED.value,
        "analysis_status": VideoProcessingStatus.QUEUED.value,
        "requeued_at": queued_at,
    }


async def get_privacy_review_queue(current_user: dict = Depends(get_current_user)):
    role = _get_user_role(current_user)
    if role != "admin":
        raise HTTPException(status_code=403, detail="Admin access required")
    videos = await db.videos.find(
        {"uploaded_by": current_user["id"], "privacy_status": PrivacyProcessingStatus.REVIEW_REQUIRED.value},
        {"_id": 0},
    ).sort("upload_date", -1).to_list(200)
    items: List[PrivacyReviewQueueItem] = []
    for video in videos:
        teacher = await db.teachers.find_one({"id": video.get("teacher_id")}, {"_id": 0, "name": 1})
        candidates = [
            PrivacyReviewCandidateTrack(**candidate)
            for candidate in (video.get("privacy_candidate_tracks") or [])
            if candidate.get("track_id")
        ]
        items.append(
            PrivacyReviewQueueItem(
                video_id=video["id"],
                teacher_id=video.get("teacher_id"),
                teacher_name=(teacher or {}).get("name"),
                filename=video.get("filename") or "recording",
                privacy_status=_normalize_privacy_status(video.get("privacy_status")),
                privacy_review_reason=video.get("privacy_review_reason"),
                upload_date=video.get("upload_date") or datetime.now(timezone.utc).isoformat(),
                candidate_tracks=candidates,
            )
        )
    return PrivacyReviewQueueResponse(items=items)


async def get_privacy_audit_events(
    target_type: Optional[str] = None,
    target_id: Optional[str] = None,
    limit: int = Query(100, ge=1, le=500),
    current_user: dict = Depends(get_current_user),
):
    role = _get_user_role(current_user)
    if role != "admin":
        raise HTTPException(status_code=403, detail="Admin access required")
    query: Dict[str, Any] = {}
    if target_type:
        query["target_type"] = target_type
    if target_id:
        query["target_id"] = target_id
    docs = await db.privacy_audit_events.find(query, {"_id": 0}).sort("created_at", -1).to_list(limit)
    return [PrivacyAuditEvent(**doc) for doc in docs]


