async def _latest_training_placement(trainee_id: str) -> Optional[dict]:
    placement = await db.trainee_placements.find_one(
        {"trainee_id": trainee_id, "status": "active"},
        {"_id": 0},
        sort=[("start_date", -1), ("created_at", -1)],
    )
