@api_router.get("/recording-policies", response_model=List[RecordingPolicy])
async def list_recording_policies(current_user: dict = Depends(get_current_user)):
    role = _get_user_role(current_user)
    if not _is_admin_role(role):
        raise HTTPException(status_code=403, detail="Only admins can access policies")
    docs = await db.recording_policies.find(
        {"created_by": current_user["id"]},
        {"_id": 0},
    ).to_list(50)
    return [RecordingPolicy(**d) for d in docs]


@api_router.post("/recording-policies", response_model=RecordingPolicy)
async def create_recording_policy(
    payload: RecordingPolicyUpsert,
    current_user: dict = Depends(get_current_user),
):
    role = _get_user_role(current_user)
    if not _is_admin_role(role):
        raise HTTPException(status_code=403, detail="Only admins can create policies")
    teacher = None
    if payload.teacher_id:
        teacher = await _get_teacher_or_404(payload.teacher_id, current_user)
    policy_query = {"created_by": current_user["id"], "teacher_id": payload.teacher_id or None}
    if payload.teacher_id:
        policy_query["teacher_id"] = payload.teacher_id
    else:
        policy_query["teacher_id"] = None
        if payload.school_id:
            policy_query["school_id"] = payload.school_id

    existing = await db.recording_policies.find_one(policy_query, {"_id": 0})
    now = datetime.now(timezone.utc).isoformat()
    if existing:
        update = payload.dict()
        update["teacher_id"] = payload.teacher_id or None
        update["updated_at"] = now
        await db.recording_policies.update_one({"id": existing["id"]}, {"$set": update})
        existing.update(update)
        return RecordingPolicy(**existing)

    doc = {
        "id": str(uuid.uuid4()),
        "created_by": current_user["id"],
        "teacher_id": payload.teacher_id or None,
        "school_id": payload.school_id or (teacher.get("school_id") if teacher else None),
        "period_length_days": payload.period_length_days,
        "min_recordings_per_period": payload.min_recordings_per_period,
        "reminder_offsets_days": payload.reminder_offsets_days,
        "created_at": now,
        "updated_at": None,
    }
    await db.recording_policies.insert_one(doc)
    return RecordingPolicy(**doc)


@api_router.patch("/recording-policies/{policy_id}", response_model=RecordingPolicy)
async def update_recording_policy(
    policy_id: str,
    payload: RecordingPolicyUpsert,
    current_user: dict = Depends(get_current_user),
):
    role = _get_user_role(current_user)
    if not _is_admin_role(role):
        raise HTTPException(status_code=403, detail="Only admins can update policies")
    if payload.teacher_id:
        await _get_teacher_or_404(payload.teacher_id, current_user)
    now = datetime.now(timezone.utc).isoformat()
    update = payload.dict()
    update["teacher_id"] = payload.teacher_id or None
    update["updated_at"] = now
    doc = await db.recording_policies.find_one_and_update(
        {"id": policy_id, "created_by": current_user["id"]},
        {"$set": update},
        return_document=True,
    )
    if not doc:
        raise HTTPException(status_code=404, detail="Policy not found")
    doc.pop("_id", None)
    return RecordingPolicy(**doc)


@api_router.get("/recording-compliance", response_model=RecordingCompliance)
async def get_recording_compliance(
    teacher_id: str,
    current_user: dict = Depends(get_current_user),
):
    teacher = await _get_teacher_or_404(teacher_id, current_user)
    admin_id = teacher.get("created_by") or current_user["id"]
    policy = await _get_recording_policy_for_teacher(admin_id, teacher)
    if not policy:
        raise HTTPException(status_code=404, detail="Recording policy not configured")
    compliance = await _upsert_recording_compliance(teacher, admin_id, policy)
    await _refresh_recording_reminders(teacher, admin_id, policy, compliance)
    return RecordingCompliance(**compliance)


@api_router.get("/recording-compliance/summary")
async def get_recording_compliance_summary(current_user: dict = Depends(get_current_user)):
    role = _get_user_role(current_user)
    if not _is_admin_role(role):
        raise HTTPException(status_code=403, detail="Only admins can access compliance summary")
    teachers = await db.teachers.find(
        {"created_by": current_user["id"]},
        {"_id": 0},
    ).to_list(1000)
    summary = []
    for teacher in teachers:
        policy = await _get_recording_policy_for_teacher(current_user["id"], teacher)
        if not policy:
            summary.append(
                {
                    "teacher_id": teacher["id"],
                    "teacher_name": teacher.get("name"),
                    "subject": teacher.get("subject"),
                    "recordings_required": 0,
                    "recordings_completed": 0,
                    "missing_subjects": [],
                    "is_compliant": False,
                    "period_end": None,
                    "policy_assigned": False,
                }
            )
            continue
        compliance = await _upsert_recording_compliance(teacher, current_user["id"], policy)
        await _refresh_recording_reminders(teacher, current_user["id"], policy, compliance)
        summary.append(
            {
                "teacher_id": teacher["id"],
                "teacher_name": teacher.get("name"),
                "subject": teacher.get("subject"),
                "recordings_required": compliance["recordings_required"],
                "recordings_completed": compliance["recordings_completed"],
                "missing_subjects": compliance["missing_subjects"],
                "is_compliant": compliance["is_compliant"],
                "period_end": compliance["period_end"],
                "policy_assigned": True,
            }
        )
    return {"policy": None, "summary": summary}


@api_router.post("/recording-compliance/remind")
async def send_recording_compliance_reminder(
    teacher_id: str = Form(...),
    current_user: dict = Depends(get_current_user),
):
    role = _get_user_role(current_user)
    if not _is_admin_role(role):
        raise HTTPException(status_code=403, detail="Only admins can send reminders")
    teacher = await _get_teacher_or_404(teacher_id, current_user)
    admin_id = current_user["id"]
    policy = await _get_recording_policy_for_teacher(admin_id, teacher)
    if not policy:
        raise HTTPException(status_code=404, detail="Recording policy not configured")
    compliance = await _upsert_recording_compliance(teacher, admin_id, policy)
    teacher_user = None
    if teacher.get("email"):
        teacher_user = await db.users.find_one(
            {"email": teacher.get("email")},
            {"_id": 0},
        )
    if not teacher_user or not teacher_user.get("id"):
        raise HTTPException(status_code=404, detail="Teacher user account not found")

    reminder = {
        "id": str(uuid.uuid4()),
        "teacher_id": teacher["id"],
        "course_name": f"Recording compliance reminder: {teacher.get('name','Teacher')}",
        "start_time": datetime.now(timezone.utc).isoformat(),
        "recording_status": ScheduleStatus.PLANNED.value,
        "join_url": None,
        "location": None,
        "user_id": teacher_user["id"],
        "created_at": datetime.now(timezone.utc).isoformat(),
        "updated_at": None,
        "reminder_type": "recording_compliance",
        "reminder_context": {
            "recordings_required": compliance["recordings_required"],
            "recordings_completed": compliance["recordings_completed"],
            "missing_subjects": compliance["missing_subjects"],
            "period_end": compliance["period_end"],
        },
        "reminder_note": "Admin reminder: submit missing lesson recordings.",
    }
    await db.schedules.insert_one(reminder)
    await _enqueue_notification(
        teacher_user,
        teacher["id"],
        "recording_compliance",
        "Recording compliance reminder",
        "Please submit missing lesson recordings for this period.",
    )
    return {"message": "Reminder sent"}


# ==================== NOTIFICATION ENDPOINTS ====================
_notification_unread_count_cache: Dict[str, Tuple[float, int]] = {}


@api_router.get("/notifications", response_model=NotificationListResponse)
async def list_notifications(
    unread_only: Optional[bool] = None,
    limit: int = 20,
    page: int = 1,
    current_user: dict = Depends(get_current_user),
):
    query: Dict[str, Any] = {
        "$or": [
            {"recipient_user_id": current_user["id"]},
            {"user_id": current_user["id"]},
        ]
    }
    if unread_only:
        query["$and"] = [{"$or": [{"read": False}, {"read": {"$exists": False}}]}, {"read_at": None}]
    limit = max(1, min(int(limit or 20), 100))
    skip = max(0, int(page or 1) - 1) * limit
    unread_query: Dict[str, Any] = {
        "$or": [
            {"recipient_user_id": current_user["id"]},
            {"user_id": current_user["id"]},
        ],
        "$and": [{"$or": [{"read": False}, {"read": {"$exists": False}}]}, {"read_at": None}],
    }
    unread_count = await db.notifications.count_documents(unread_query)
    notifications = await db.notifications.find(
        query,
        {"_id": 0, "user_id": 0},
    ).sort("created_at", -1).skip(skip).to_list(limit)
    return NotificationListResponse(
        items=[NotificationRecord(**_sanitize_notification_doc(n)) for n in notifications],
        unread_count=unread_count,
    )


@api_router.get("/notifications/unread-count")
async def get_notification_unread_count(current_user: dict = Depends(get_current_user)):
    cached = _notification_unread_count_cache.get(current_user["id"])
    now_ts = time.time()
    if cached and now_ts - cached[0] < 30:
        return {"count": cached[1]}
    unread_query: Dict[str, Any] = {
        "$or": [
            {"recipient_user_id": current_user["id"]},
            {"user_id": current_user["id"]},
        ],
        "$and": [{"$or": [{"read": False}, {"read": {"$exists": False}}]}, {"read_at": None}],
    }
    count = await db.notifications.count_documents(unread_query)
    _notification_unread_count_cache[current_user["id"]] = (now_ts, count)
    return {"count": count}


@api_router.post("/notifications/{notification_id}/read", response_model=NotificationRecord)
async def mark_notification_read(
    notification_id: str,
    current_user: dict = Depends(get_current_user),
):
    read_at = datetime.now(timezone.utc).isoformat()
    result = await db.notifications.find_one_and_update(
        {
            "id": notification_id,
            "$or": [
                {"recipient_user_id": current_user["id"]},
                {"user_id": current_user["id"]},
            ],
        },
        {"$set": {"read": True, "read_at": read_at}},
        return_document=True,
        projection={"_id": 0, "user_id": 0},
    )
    if not result:
        raise HTTPException(status_code=404, detail="Notification not found")
    _notification_unread_count_cache.pop(current_user["id"], None)
    return NotificationRecord(**_sanitize_notification_doc(result))


@api_router.post("/notifications/read-all")
async def mark_all_notifications_read(current_user: dict = Depends(get_current_user)):
    read_at = datetime.now(timezone.utc).isoformat()
    result = await db.notifications.update_many(
        {
            "$or": [
                {"recipient_user_id": current_user["id"]},
                {"user_id": current_user["id"]},
            ],
            "$and": [{"$or": [{"read": False}, {"read": {"$exists": False}}]}, {"read_at": None}],
        },
        {"$set": {"read": True, "read_at": read_at}},
    )
    _notification_unread_count_cache.pop(current_user["id"], None)
    return {"updated_count": result.modified_count, "read_at": read_at}


@api_router.post("/notifications/mark-all-read")
async def mark_all_notifications_read_alias(current_user: dict = Depends(get_current_user)):
    return await mark_all_notifications_read(current_user=current_user)


@api_router.delete("/notifications/{notification_id}")
async def dismiss_notification(
    notification_id: str,
    current_user: dict = Depends(get_current_user),
):
    result = await db.notifications.delete_one(
        {
            "id": notification_id,
            "$or": [
                {"recipient_user_id": current_user["id"]},
                {"user_id": current_user["id"]},
            ],
        }
    )
    if result.deleted_count == 0:
        raise HTTPException(status_code=404, detail="Notification not found")
    _notification_unread_count_cache.pop(current_user["id"], None)
    return {"deleted": True}


def _default_notification_preferences(user_id: str) -> dict:
    now = datetime.now(timezone.utc).isoformat()
    return {
        "id": user_id,
        "user_id": user_id,
        "email_observation_complete": True,
        "email_goal_added": True,
        "email_recognition": True,
        "email_conference_reminder": True,
        "email_frequency": "immediate",
        "created_at": now,
        "updated_at": None,
    }


@api_router.get("/user/notification-preferences")
async def get_notification_preferences(current_user: dict = Depends(get_current_user)):
    prefs = await db.notification_preferences.find_one(
        {"user_id": current_user["id"]},
        {"_id": 0},
    )
    return prefs or _default_notification_preferences(current_user["id"])


@api_router.patch("/user/notification-preferences")
async def update_notification_preferences(
    payload: NotificationPreferencesPayload,
    current_user: dict = Depends(get_current_user),
):
    frequency = (payload.email_frequency or "immediate").strip().lower()
    if frequency not in {"immediate", "daily_digest", "off"}:
        raise HTTPException(status_code=400, detail="Unsupported email frequency")
    now = datetime.now(timezone.utc).isoformat()
    update_doc = payload.dict()
    update_doc["email_frequency"] = frequency
    update_doc["updated_at"] = now
    existing = await db.notification_preferences.find_one({"user_id": current_user["id"]}, {"_id": 0})
    if not existing:
        update_doc.update({"id": current_user["id"], "user_id": current_user["id"], "created_at": now})
        await db.notification_preferences.insert_one(update_doc)
    else:
        await db.notification_preferences.update_one(
            {"user_id": current_user["id"]},
            {"$set": update_doc},
        )
    return await get_notification_preferences(current_user=current_user)


@api_router.get("/admin/email-preview/{template_name}")
async def preview_email_template(
    template_name: str,
    current_user: dict = Depends(get_current_user),
):
    if _get_user_tenant_role(current_user) != "super_admin":
        raise HTTPException(status_code=403, detail="Master admin access required")
    from app.services.notification_service import NotificationService

    try:
        return {"template_name": template_name, "html": NotificationService().preview(template_name)}
    except KeyError:
        raise HTTPException(status_code=404, detail="Unknown email template")


# ==================== ONBOARDING / CONSENT / TELEMETRY ====================
ONBOARDING_STEP_ORDER = [
    "workspace_configured",
    "framework_selected",
    "first_teacher_added",
    "observation_settings_configured",
    "first_video_uploaded",
    "first_analysis_complete",
]
CONSENT_TYPES = ["video_recording", "data_processing", "ai_analysis"]


def _workspace_id_for_user(current_user: dict) -> str:
    return str(current_user.get("organization_id") or current_user.get("school_id") or current_user.get("id"))


async def _workspace_doc_for_user(current_user: dict) -> Tuple[str, dict, str]:
    workspace_id = _workspace_id_for_user(current_user)
    if current_user.get("organization_id"):
        doc = await db.organizations.find_one({"id": current_user["organization_id"]}, {"_id": 0}) or {}
        return workspace_id, doc, "organizations"
    doc = await db.users.find_one({"id": current_user["id"]}, {"_id": 0, "password": 0}) or current_user
    return workspace_id, doc, "users"


def _default_onboarding_steps() -> Dict[str, Any]:
    steps = {step: False for step in ONBOARDING_STEP_ORDER}
    steps["completed_at"] = None
    return steps


async def _derive_onboarding_steps(current_user: dict, stored: Optional[dict] = None) -> Dict[str, Any]:
    steps = {**_default_onboarding_steps(), **(stored or {})}
    workspace_id = _workspace_id_for_user(current_user)
    user_id = current_user["id"]
    if current_user.get("organization_id") or current_user.get("school_name") or current_user.get("organization_name"):
        steps["workspace_configured"] = True
    if await db.framework_selections.find_one({"user_id": user_id}, {"_id": 1}):
        steps["framework_selected"] = True
    if await db.teachers.count_documents({"$or": [{"created_by": user_id}, {"organization_id": workspace_id}, {"school_id": workspace_id}]}) > 0:
        steps["first_teacher_added"] = True
    if await db.recording_policies.find_one({"$or": [{"created_by": user_id}, {"workspace_id": workspace_id}]}, {"_id": 1}):
        steps["observation_settings_configured"] = True
    if await db.videos.count_documents({"$or": [{"uploaded_by": user_id}, {"workspace_id": workspace_id}]}) > 0:
        steps["first_video_uploaded"] = True
    if await db.assessments.count_documents({"$or": [{"user_id": user_id}, {"workspace_id": workspace_id}]}) > 0:
        steps["first_analysis_complete"] = True
    if all(steps.get(step) for step in ONBOARDING_STEP_ORDER) and not steps.get("completed_at"):
        steps["completed_at"] = datetime.now(timezone.utc).isoformat()
    return steps


async def _onboarding_count(collection_name: str, query: dict) -> int:
    collection = getattr(db, collection_name, None)
    if collection is None:
        return 0
    return await collection.count_documents(query)


async def _build_onboarding_status_payload(current_user: dict, doc: dict, steps: dict) -> dict:
    tenant_role = _get_user_tenant_role(current_user)
    if tenant_role == "teacher":
        raise HTTPException(status_code=403, detail="Teacher onboarding lives in your workspace.")

    workspace_id = _workspace_id_for_user(current_user)
    workspace_mode = _dashboard_workspace_mode(current_user)
    teacher_ids = await _list_teacher_ids_for_user(current_user)
    teacher_filter = {"teacher_id": {"$in": teacher_ids or ["__none__"]}}
    video_filter = {
        "$or": [
            {"teacher_id": {"$in": teacher_ids or ["__none__"]}},
            {"workspace_id": workspace_id},
            {"uploaded_by": current_user["id"]},
        ]
    }
    assessment_filter = {
        "$or": [
            {"teacher_id": {"$in": teacher_ids or ["__none__"]}},
            {"workspace_id": workspace_id},
            {"user_id": current_user["id"]},
        ]
    }

    planned_observations = await _onboarding_count("observation_sessions", teacher_filter)
    if planned_observations == 0:
        planned_observations = await _onboarding_count("observations", teacher_filter)
    uploaded_recordings = await _onboarding_count("videos", video_filter)
    reviewed_lessons = await _onboarding_count("assessments", assessment_filter)
    open_tasks = await _onboarding_count(
        "coaching_tasks",
        {**teacher_filter, "status": {"$nin": ["completed", "done", "archived", "deleted"]}},
    )

    is_training = workspace_mode == "training"
    people_label = "trainees" if is_training else "teachers"
    person_label = "trainee" if is_training else "teacher"
    org_complete = bool(
        current_user.get("organization_name")
        or current_user.get("school_name")
        or doc.get("name")
        or doc.get("organization_name")
    )
    counts = {
        "teachers": 0 if is_training else len(teacher_ids),
        "trainees": len(teacher_ids) if is_training else 0,
        "planned_observations": planned_observations,
        "uploaded_recordings": uploaded_recordings,
        "reviewed_lessons": reviewed_lessons,
        "open_coaching_tasks": open_tasks,
    }
    step_defs = [
        {
            "id": "organization_profile",
            "title": "Confirm your workspace",
            "description": "Name the school or program so everyone knows where this coaching work lives.",
            "status": "complete" if org_complete else "incomplete",
            "href": "/school-setup" if workspace_mode == "school" else "/onboarding",
            "count": None,
        },
        {
            "id": "add_teachers",
            "title": f"Add your first {person_label}",
            "description": (
                "Add trainees so you can plan placement observations."
                if is_training
                else "Add teachers so you can plan focused observations."
            ),
            "status": "complete" if len(teacher_ids) > 0 else "incomplete",
            "href": "/teachers",
            "count": len(teacher_ids),
        },
        {
            "id": "plan_observation",
            "title": "Plan a focused observation" if not is_training else "Plan a trainee observation",
            "description": "Choose what Cognivio should pay attention to before the recording is uploaded.",
            "status": "complete" if planned_observations > 0 else "incomplete",
            "href": "/observation/new",
            "count": planned_observations,
        },
        {
            "id": "upload_recording",
            "title": "Record or upload a lesson" if not is_training else "Record or upload an observation",
            "description": "Connect the recording to the observation focus you saved.",
            "status": "complete" if uploaded_recordings > 0 else "incomplete",
            "href": "/record",
            "count": uploaded_recordings,
        },
        {
            "id": "review_feedback",
            "title": "Review the first coaching summary" if not is_training else "Review trainee observation feedback",
            "description": "Once one recording has been reviewed, your dashboard will start showing coaching patterns.",
            "status": "complete" if reviewed_lessons > 0 else "incomplete",
            "href": "/dashboard",
            "count": reviewed_lessons,
        },
        {
            "id": "invite_team",
            "title": "Invite the team when you are ready",
            "description": f"Keep this optional while you rehearse the flow with internal {people_label}.",
            "status": "optional",
            "href": "/teachers",
            "count": None,
        },
    ]
    required_steps = [step for step in step_defs if step["status"] != "optional"]
    complete_required = sum(1 for step in required_steps if step["status"] == "complete")
    progress_pct = round((complete_required / len(required_steps)) * 100) if required_steps else 100
    if len(teacher_ids) == 0:
        progress_pct = 0
    next_step = next((step for step in step_defs if step["status"] == "incomplete"), None)
    if next_step is None:
        next_step = {
            "id": "dashboard",
            "title": "You are ready to use the dashboard",
            "description": "Review priorities, plan the next observation, and open reports when you need a shareable snapshot.",
            "href": "/dashboard",
            "cta_label": "Open dashboard",
        }
    else:
        next_step = {
            "id": next_step["id"],
            "title": next_step["title"],
            "description": next_step["description"],
            "href": next_step["href"],
            "cta_label": (
                "Add trainee" if next_step["id"] == "add_teachers" and is_training
                else "Add teacher" if next_step["id"] == "add_teachers"
                else "Plan observation" if next_step["id"] == "plan_observation"
                else "Record or upload" if next_step["id"] == "upload_recording"
                else "Open dashboard"
            ),
        }
    completed = all(step["status"] == "complete" for step in required_steps)
    legacy_completed_count = sum(1 for step in ONBOARDING_STEP_ORDER if steps.get(step))
    return {
        "workspace_id": workspace_id,
        "workspace_mode": workspace_mode,
        "completed": completed,
        "progress_pct": progress_pct,
        "next_step": next_step,
        "steps": step_defs,
        "counts": counts,
        "onboarding_steps": steps,
        "completed_count": legacy_completed_count,
        "total_steps": len(ONBOARDING_STEP_ORDER),
        "is_complete": completed,
    }


async def _persist_onboarding_steps(current_user: dict, steps: dict) -> None:
    _, _, collection_name = await _workspace_doc_for_user(current_user)
    target = {"id": current_user.get("organization_id") or current_user["id"]}
    await getattr(db, collection_name).update_one(
        target,
        {"$set": {"onboarding_steps": steps, "updated_at": datetime.now(timezone.utc).isoformat()}},
    )


@api_router.get("/onboarding/status")
async def get_onboarding_status(current_user: dict = Depends(get_current_user)):
    _, doc, _ = await _workspace_doc_for_user(current_user)
    steps = await _derive_onboarding_steps(current_user, doc.get("onboarding_steps") or {})
    if steps != (doc.get("onboarding_steps") or {}):
        await _persist_onboarding_steps(current_user, steps)
    return await _build_onboarding_status_payload(current_user, doc, steps)


@api_router.post("/onboarding/complete")
async def complete_onboarding(
    payload: OnboardingCompletePayload,
    current_user: dict = Depends(get_current_user),
):
    _, doc, _ = await _workspace_doc_for_user(current_user)
    steps = {**_default_onboarding_steps(), **(doc.get("onboarding_steps") or {})}
    if payload.steps:
        for key, value in payload.steps.items():
            if key in ONBOARDING_STEP_ORDER:
                steps[key] = bool(value)
    if payload.step in ONBOARDING_STEP_ORDER:
        steps[payload.step] = True
    if payload.completed or all(steps.get(step) for step in ONBOARDING_STEP_ORDER):
        for step in ONBOARDING_STEP_ORDER:
            steps[step] = True
        steps["completed_at"] = steps.get("completed_at") or datetime.now(timezone.utc).isoformat()
    await _persist_onboarding_steps(current_user, steps)
    return await get_onboarding_status(current_user=current_user)


async def _latest_consent_status(user_id: str, workspace_id: Optional[str] = None) -> Dict[str, dict]:
    query: Dict[str, Any] = {"user_id": user_id}
    if workspace_id:
        query["workspace_id"] = workspace_id
    records = await db.consent_records.find(query, {"_id": 0}).sort("created_at", -1).to_list(100)
    status = {}
    for consent_type in CONSENT_TYPES:
        record = next((item for item in records if item.get("consent_type") == consent_type), None)
        status[consent_type] = record or {"consent_type": consent_type, "granted": False}
    return status


async def _teacher_has_required_consents(teacher: dict) -> bool:
    email = str((teacher or {}).get("email") or "").strip()
    user_doc = await _find_user_by_email(email) if email else None
    if not user_doc:
        return False
    status = await _latest_consent_status(user_doc["id"], teacher.get("organization_id") or teacher.get("school_id"))
    return all((status.get(kind) or {}).get("granted") is True and not (status.get(kind) or {}).get("withdrawn_at") for kind in CONSENT_TYPES)


