@api_router.post("/master-admin/organizations/{organization_id}/seat-policy", response_model=MasterAdminOrganizationRecord)
async def update_master_admin_organization_seat_policy(
    organization_id: str,
    payload: MasterAdminOrganizationSeatPolicyPayload,
    current_user: dict = Depends(get_current_user),
):
    _require_master_admin_user(current_user)
    organization_doc = await db.organizations.find_one({"id": organization_id}, {"_id": 0})
    if not organization_doc:
        raise HTTPException(status_code=404, detail="Organization not found")
    seat_limit = _normalize_seat_limit(payload.seat_limit)
    await db.organizations.update_one(
        {"id": organization_id},
        {"$set": {"seat_limit": seat_limit, "seat_policy_updated_at": datetime.now(timezone.utc).isoformat()}},
    )
    updated = await db.organizations.find_one({"id": organization_id}, {"_id": 0})
    await _log_master_admin_audit_event(
        actor=current_user,
        action="update_organization_seat_policy",
        target_type="organization",
        target_id=organization_id,
        reason=payload.reason,
        metadata={"name": updated.get("name"), "seat_limit": seat_limit},
    )
    return await _build_master_admin_organization_record(updated)


def _build_master_admin_user_action_response(
    updated: dict,
    *,
    action: str,
    status: str,
) -> MasterAdminUserActionResponse:
    attempted = bool(updated.get("_email_delivery_attempted"))
    sent = bool(updated.get("_email_delivery_succeeded"))
    warning = None
    if attempted and not sent:
        warning = "Email could not be sent. Check Resend health before relying on email delivery."
    message_action = "Approved" if status == "approved" else "Rejected"
    message = (
        f"{message_action}. Confirmation email sent."
        if sent
        else f"{message_action}. Email could not be sent; check Resend health."
        if attempted
        else f"{message_action}."
    )
    record = _model_public_dict(_to_access_user_record(updated))
    return MasterAdminUserActionResponse(
        **record,
        ok=True,
        action=action,
        user_id=updated.get("id") or record.get("id"),
        status=status,
        message=message,
        email_status=AccessActionEmailStatus(attempted=attempted, sent=sent, warning=warning),
    )


@api_router.post("/master-admin/users/{user_id}/approve", response_model=MasterAdminUserActionResponse)
async def master_admin_approve_user(
    user_id: str,
    payload: MasterAdminUserActionPayload,
    current_user: dict = Depends(get_current_user),
):
    _require_master_admin_user(current_user)
    target = await db.users.find_one({"id": user_id}, {"_id": 0, "password": 0})
    if not target:
        raise HTTPException(status_code=404, detail="User not found")
    updated = await _approve_user_access(
        target,
        actor_label=current_user.get("email") or current_user["id"],
        reason=payload.reason,
        organization_name=payload.organization_name,
        organization_type=payload.organization_type,
        school_name=payload.school_name,
        manager_email=payload.manager_email,
    )
    await _log_master_admin_audit_event(
        actor=current_user,
        action="approve_user_access",
        target_type="user",
        target_id=user_id,
        reason=payload.reason,
        metadata={
            "email": updated.get("email"),
            "approval_status": updated.get("approval_status"),
            "tenant_role": updated.get("tenant_role"),
            "organization_name": updated.get("organization_name") or updated.get("requested_organization_name"),
            "school_name": updated.get("school_name") or updated.get("requested_school_name"),
            "manager_email": updated.get("manager_email") or updated.get("requested_manager_email"),
        },
    )
    return _build_master_admin_user_action_response(updated, action="approve", status="approved")


@api_router.post("/master-admin/users/{user_id}/revoke", response_model=AccessUserRecord)
async def master_admin_revoke_user(
    user_id: str,
    payload: MasterAdminUserActionPayload,
    current_user: dict = Depends(get_current_user),
):
    _require_master_admin_user(current_user)
    if user_id == current_user.get("id"):
        raise HTTPException(status_code=400, detail="You cannot revoke your own access")
    target = await db.users.find_one({"id": user_id}, {"_id": 0, "password": 0})
    if not target:
        raise HTTPException(status_code=404, detail="User not found")
    if not payload.reason:
        raise HTTPException(status_code=400, detail="A reason is required before access can be revoked")
    updated = await _revoke_user_access(
        target,
        actor_label=current_user.get("email") or current_user["id"],
        reason=payload.reason,
    )
    await _log_master_admin_audit_event(
        actor=current_user,
        action="revoke_user_access",
        target_type="user",
        target_id=user_id,
        reason=payload.reason,
        metadata={"email": updated.get("email"), "approval_status": updated.get("approval_status")},
    )
    return _to_access_user_record(updated)


@api_router.post("/master-admin/users/{user_id}/freeze", response_model=AccessUserRecord)
async def master_admin_freeze_user(
    user_id: str,
    payload: MasterAdminUserActionPayload,
    current_user: dict = Depends(get_current_user),
):
    return await master_admin_revoke_user(user_id, payload, current_user=current_user)


@api_router.post("/master-admin/users/{user_id}/delete", response_model=MasterAdminUserActionResponse)
async def master_admin_delete_user(
    user_id: str,
    payload: MasterAdminUserActionPayload,
    current_user: dict = Depends(get_current_user),
):
    _require_master_admin_user(current_user)
    if user_id == current_user.get("id"):
        raise HTTPException(status_code=400, detail="You cannot delete your own access")
    target = await db.users.find_one({"id": user_id}, {"_id": 0, "password": 0})
    if not target:
        raise HTTPException(status_code=404, detail="User not found")
    expected_confirmation = str(target.get("email") or "").strip().lower()
    actual_confirmation = str(payload.confirmation_text or payload.confirmation_email or "").strip().lower()
    if not payload.reason:
        raise HTTPException(status_code=400, detail="A reason is required before access can be deleted")
    if expected_confirmation and actual_confirmation != expected_confirmation:
        raise HTTPException(status_code=400, detail="Confirmation text must match the target email exactly")
    deleted = await _hard_delete_user_access(
        target,
        actor=current_user,
        reason=payload.reason,
    )
    await _log_master_admin_audit_event(
        actor=current_user,
        action="delete_user_access",
        target_type="user",
        target_id=user_id,
        reason=payload.reason,
        metadata={
            "email": deleted.get("email"),
            "approval_status": deleted.get("approval_status"),
            "deleted_counts": deleted.get("deleted_counts") or {},
        },
    )
    action = "reject" if deleted.get("approval_deleted") else "delete"
    status = "rejected" if deleted.get("approval_deleted") else "deleted"
    return _build_master_admin_user_action_response(deleted, action=action, status=status)


